// Extract per-tweet metrics from Twitter API v2 response
const response = $input.first().json;
const tweets = response.data || [];
const users = (response.includes?.users || []).reduce((map, u) => {
  map[u.id] = u;
  return map;
}, {});

if (tweets.length === 0) {
  return [{ json: { tweets: [], tweetCount: 0, hasResults: false } }];
}

const enriched = tweets.map(tweet => {
  const metrics = tweet.public_metrics || {};
  const author = users[tweet.author_id] || {};
  return {
    id: tweet.id,
    text: tweet.text,
    authorId: tweet.author_id,
    authorUsername: author.username || 'unknown',
    authorName: author.name || '',
    createdAt: tweet.created_at,
    retweets: metrics.retweet_count || 0,
    likes: metrics.like_count || 0,
    replies: metrics.reply_count || 0,
    impressions: metrics.impression_count || 0,
    quoteCount: metrics.quote_count || 0,
    tweetUrl: `https://twitter.com/i/web/status/${tweet.id}`
  };
});

return [{ json: { tweets: enriched, tweetCount: enriched.length, hasResults: true } }];

// Calculate raid performance scores and rank tweets
// Score = (retweets * 3) + (likes * 1) + (replies * 2)

const d = $input.first().json;

if (!d.hasResults || d.tweets.length === 0) {
  return [{ json: { ...d, scoredTweets: [], topTweet: null, totalImpressions: 0, hasHighPerformer: false } }];
}

const scored = d.tweets.map(tweet => ({
  ...tweet,
  score: (tweet.retweets * 3) + (tweet.likes * 1) + (tweet.replies * 2)
}));

// Sort by score descending
scored.sort((a, b) => b.score - a.score);

const topTweet = scored[0];
const totalImpressions = scored.reduce((sum, t) => sum + t.impressions, 0);
const totalRetweets = scored.reduce((sum, t) => sum + t.retweets, 0);
const totalLikes = scored.reduce((sum, t) => sum + t.likes, 0);
const totalReplies = scored.reduce((sum, t) => sum + t.replies, 0);
const hasHighPerformer = topTweet && topTweet.score > 50;

return [{
  json: {
    scoredTweets: scored,
    tweetCount: d.tweetCount,
    topTweet,
    totalImpressions,
    totalRetweets,
    totalLikes,
    totalReplies,
    hasHighPerformer,
    checkTimestamp: new Date().toISOString()
  }
}];

// Build Telegram raid report message
const d = $input.first().json;
const top = d.topTweet;

const impressionsFmt = new Intl.NumberFormat('en-US').format(d.totalImpressions);
const tweetPreview = top.text.length > 60 ? top.text.slice(0, 60) + '...' : top.text;

const message = `⚔️ RAID REPORT\n\n` +
  `📊 Tweets tracked: ${d.tweetCount}\n` +
  `🔥 Top performer:\n` +
  `   @${top.authorUsername}\n` +
  `   "${tweetPreview}"\n` +
  `   Score: ${top.score} (RT:${top.retweets} ❤️:${top.likes} 💬:${top.replies})\n` +
  `   🔗 [View Tweet](${top.tweetUrl})\n\n` +
  `📈 Total reach: ${impressionsFmt} impressions\n` +
  `🔁 Total retweets: ${d.totalRetweets}\n` +
  `❤️ Total likes: ${d.totalLikes}\n` +
  `💬 Total replies: ${d.totalReplies}\n\n` +
  `Keep raiding! 🚀 #YST #YakkStudios`;

return [{ json: { ...d, telegramMessage: message } }];
